const _hoisted_333 = /* @__PURE__ */ createStaticVNode('<h3 id="\u4FDD\u5B58\u8FDB\u7A0B\u5217\u8868" tabindex="-1"><a class="header-anchor" href="#\u4FDD\u5B58\u8FDB\u7A0B\u5217\u8868" aria-hidden="true">#</a> \u4FDD\u5B58\u8FDB\u7A0B\u5217\u8868</h3><p>\u82E5\u662F\u4F60\u4E4B\u524D\u4FDD\u5B58\u8FC7\u8FDB\u7A0B\u5217\u8868\uFF0C<code>startup</code>\u94A9\u5B50\u4F1A\u81EA\u52A8\u52A0\u8F7D\u8FDB\u7A0B\u5217\u8868\u3002</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># \u4FDD\u5B58\u8FDB\u7A0B\u5217\u8868</span>\npm2 save\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="custom-container warning"><p class="custom-container-title">\u8B66\u544A</p><p>\u82E5\u662F\u4F60\u5220\u9664\u4E86\u6240\u6709\u7684\u8FDB\u7A0B\uFF0C\u4E4B\u540E\u91CD\u542F\u7CFB\u7EDF\uFF08\u6216\u4F7F\u7528<code>pm2 update</code>\uFF09\uFF0C\u5219\u7CFB\u7EDF\u5C06\u6062\u590D\u4F60\u6240\u6709\u7684\u8FDB\u7A0B\uFF08\u4E4B\u524D\u5B58\u50A8\u5728<code>dump</code>\u6587\u4EF6\u91CC\uFF09\uFF0C\u8FD9\u662F\u4E3A\u4E86\u9632\u6B62<code>empty dump file</code>\u7684 BUG\u3002</p></div><p>\u82E5\u662F\u4F60\u60F3\u521B\u5EFA\u7A7A\u7684<code>dump</code>\u6587\u4EF6\uFF0C\u4F60\u5E94\u8BE5\u6267\u884C\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 cleartdump\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="\u7981\u7528-startup-\u7CFB\u7EDF" tabindex="-1"><a class="header-anchor" href="#\u7981\u7528-startup-\u7CFB\u7EDF" aria-hidden="true">#</a> \u7981\u7528 startup \u7CFB\u7EDF</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 unstartup\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="\u7528\u6237\u6388\u6743" tabindex="-1"><a class="header-anchor" href="#\u7528\u6237\u6388\u6743" aria-hidden="true">#</a> \u7528\u6237\u6388\u6743</h3><p>\u82E5\u662F\u4F60\u60F3\u8981<code>startup</code>\u94A9\u5B50\u5728\u5176\u4ED6\u7528\u6237\u4E0B\u6267\u884C\uFF0C\u4F7F\u7528<code>-u &lt;username&gt;</code>\u9009\u9879\u548C<code>--hp &lt;user_home&gt;</code>\u9009\u9879\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 startup ubuntu -u www --hp /home/ubuntu\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="\u66F4\u65B0-startup-\u94A9\u5B50" tabindex="-1"><a class="header-anchor" href="#\u66F4\u65B0-startup-\u94A9\u5B50" aria-hidden="true">#</a> \u66F4\u65B0 startup \u94A9\u5B50</h3><p>\u6267\u884C\u4EE5\u4E0B\u547D\u4EE4\u6765\u5347\u7EA7<code>startup</code>\u94A9\u5B50\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 unstartup\npm2 startup\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="\u517C\u5BB9\u6027" tabindex="-1"><a class="header-anchor" href="#\u517C\u5BB9\u6027" aria-hidden="true">#</a> \u517C\u5BB9\u6027</h3><p>\u652F\u6301\u7684\u521D\u59CB\u5316\u7CFB\u7EDF\u6709\uFF1A</p><p><code>systemd</code>: Ubuntu &gt;= 16, CentOS &gt;= 7, Arch, Debian &gt;= 7 <code>upstart</code>: Ubuntu &lt;= 14 <code>launchd</code>: Darwin, MacOSx <code>openrc</code>: Gentoo Linux, Arch Linux <code>rcd</code>: FreeBSD <code>systemv</code>: Centos 6, Amazon Linux</p><p>\u4F60\u53EF\u4EE5\u6307\u5B9A\u4F60\u4F7F\u7528\u7684\u5E73\u53F0\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 <span class="token punctuation">[</span>startup <span class="token operator">|</span> unstartup<span class="token punctuation">]</span> <span class="token punctuation">[</span>platform<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>\u5E73\u53F0\u53EF\u4EE5\u662F\u4E0B\u9762\u8FD9\u4E9B\u4E2D\u7684\u4E00\u79CD\uFF1A</p><ul><li><code>ubuntu</code></li><li><code>ubuntu14</code></li><li><code>ubuntu12</code></li><li><code>centos</code></li><li><code>centos6</code></li><li><code>arch</code></li><li><code>oracle</code></li><li><code>amazon</code></li><li><code>macos</code></li><li><code>darwin</code></li><li><code>freebsd</code></li><li><code>systemd</code></li><li><code>systemv</code></li><li><code>upstart</code></li><li><code>launchd</code></li><li><code>rcd</code></li><li><code>openrc</code></li></ul><h3 id="under-the-hoodlink" tabindex="-1"><a class="header-anchor" href="#under-the-hoodlink" aria-hidden="true">#</a> Under the hoodlink</h3><ul><li><code>ubuntu</code> use <code>updaterc.d</code> and the script <code>lib/scripts/pm2-init.sh</code></li><li><code>centos</code>/<code>redhat</code> use <code>chkconfig</code> and the script <code>lib/scripts/pm2-init-centos.sh</code></li><li><code>gentoo</code> use <code>rc-update</code> and the script <code>lib/scripts/pm2</code></li><li><code>systemd</code> use <code>systemctl</code> and the script <code>lib/scripts/pm2.service</code></li><li><code>darwin</code> use <code>launchd</code> to load a specific <code>plist</code> to resurrect processes after reboot.</li></ul><h2 id="\u5165\u53E3\u70B9" tabindex="-1"><a class="header-anchor" href="#\u5165\u53E3\u70B9" aria-hidden="true">#</a> \u5165\u53E3\u70B9</h2><h2 id="\u5185\u5B58\u9608\u503C-\u81EA\u52A8\u91CD\u8F7D" tabindex="-1"><a class="header-anchor" href="#\u5185\u5B58\u9608\u503C-\u81EA\u52A8\u91CD\u8F7D" aria-hidden="true">#</a> \u5185\u5B58\u9608\u503C\uFF0C\u81EA\u52A8\u91CD\u8F7D</h2><p>PM2 \u5141\u8BB8\u5728\u5185\u5B58\u5230\u8FBE\u6307\u5B9A\u7684\u9608\u503C\u540E\uFF0C\u91CD\u8F7D<code>reload</code>\u5E94\u7528\uFF08\u82E5\u4E0D\u662F<code>cluster</code>\u6A21\u5F0F\uFF0C\u5219\u81EA\u52A8\u964D\u7EA7\u4E3A\u91CD\u542F<code>restart</code>\uFF09\u3002</p><p>\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0CPM2 \u5185\u90E8\u8D1F\u8D23\u68C0\u67E5\u5185\u5B58\u7684<code>worker</code>\u6BCF 30s \u91CD\u542F\u4E00\u6B21\uFF0C\u56E0\u6B64\u53EF\u80FD\u5728\u5E94\u7528\u8FBE\u5230\u5185\u5B58\u9608\u503C\u4E4B\u540E\uFF0C\u8FD8\u9700\u8981\u7B49\u4E00\u4F1A\u513F\u624D\u4F1A\u81EA\u52A8\u91CD\u8F7D\u5E94\u7528\u3002</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># \u901A\u8FC7 CLI \u8BBE\u7F6E\u6700\u5927\u5185\u5B58\u9608\u503C</span>\npm2 start api.js --max-memory-restart 300M\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// \u751F\u6001\u7CFB\u7EDF\u6587\u4EF6</span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  apps<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span>\n    name<span class="token operator">:</span> <span class="token string">&#39;api&#39;</span><span class="token punctuation">,</span>\n    script<span class="token operator">:</span> <span class="token string">&#39;api.js&#39;</span><span class="token punctuation">,</span>\n    max_memory_restart<span class="token operator">:</span> <span class="token string">&#39;300M&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>PS: \u5355\u4F4D\u53EF\u4EE5\u662F K(ilobyte), M(egabyte), G(igabyte).</p><h2 id="\u5347\u7EA7-pm2" tabindex="-1"><a class="header-anchor" href="#\u5347\u7EA7-pm2" aria-hidden="true">#</a> \u5347\u7EA7 PM2</h2><p>\u5347\u7EA7 PM2 \u662F\u76F8\u5F53\u7B80\u5355\u7684\u64CD\u4F5C\u3002\u5347\u7EA7<code>minor</code>/<code>patch</code>\u7248\u672C\uFF08\u5373\u5347\u7EA7<code>x.y.z</code>\u4E2D\u7684<code>y</code>\u6216<code>z</code>\u7248\u672C\uFF09\u4E0D\u9700\u8981\u7834\u574F\u4EFB\u4F55\u73AF\u5883\u3002\u4F60\u53EA\u9700\uFF1A</p><ol><li>\u5B89\u88C5\u6700\u65B0\u7248\u7684 PM2\uFF0C<code>npm install pm2@latest -g</code></li><li>\u4FDD\u5B58\u5F53\u524D\u8FDB\u7A0B\u5217\u8868\uFF0C\u6740\u6389\u4EE5\u524D\u7684 PM2 \u5B88\u62A4\u8FDB\u7A0B\uFF0C\u6062\u590D\u8FDB\u7A0B\u5217\u8868\uFF0C\u8FD9\u51E0\u6B65\u4EC5\u9700\u6267\u884C<code>pm2 update</code></li></ol><h2 id="source-map-\u652F\u6301" tabindex="-1"><a class="header-anchor" href="#source-map-\u652F\u6301" aria-hidden="true">#</a> Source Map \u652F\u6301</h2><p>\u82E5\u662F\u4F60\u4F7F\u7528<code>BabelJS</code>/<code>Typescript</code>\uFF0C\u6216\u5176\u4ED6 Javascript \u8D85\u96C6\u8BED\u8A00\uFF0C\u4F60\u53EF\u80FD\u5DF2\u7ECF\u53D1\u73B0\uFF1A\u5F53\u53D1\u751F\u5F02\u5E38\u65F6\uFF0C\u9519\u8BEF\u5806\u6808\u8FFD\u8E2A\u4FE1\u606F\u6BEB\u65E0\u7528\u5904\u3002\u82E5\u662F\u60F3\u8981\u83B7\u5F97\u6709\u7528\u7684\u4FE1\u606F\uFF0C\u9700\u8981\u751F\u6210 Source Map \u6587\u4EF6\u3002</p><p>\u4E00\u65E6 Source Map \u6587\u4EF6\u751F\u6210\u4E4B\u540E\uFF0CPM2 \u5C06\u81EA\u52A8\u53D1\u73B0\u5E76\u5E2E\u52A9\u4F60\u68C0\u67E5\u9519\u8BEF\u3002\u82E5\u662F\u4F60\u542F\u52A8\u7684\u5E94\u7528\uFF08\u6BD4\u5982<code>app.js</code>\uFF09\u6709\u4E0E\u4E4B\u5BF9\u5E94\u7684 Map \u6587\u4EF6\uFF08\u6BD4\u5982<code>app.js.map</code>\uFF09\uFF0CPM2 \u5C06\u81EA\u52A8\u68C0\u67E5\u5230 JS Source Map \u6587\u4EF6\u3002</p><h3 id="\u68C0\u67E5\u5F02\u5E38" tabindex="-1"><a class="header-anchor" href="#\u68C0\u67E5\u5F02\u5E38" aria-hidden="true">#</a> \u68C0\u67E5\u5F02\u5E38</h3><p>\u5F02\u5E38\u4F1A\u88AB\u8BB0\u5F55\u5230\u5E94\u7528\u7684\u9519\u8BEF\u65E5\u5FD7\u6587\u4EF6\u91CC\uFF0C\u8981\u60F3\u68C0\u67E5\u65E5\u5FD7\u53BB\u53D1\u73B0\u5F02\u5E38\uFF0C\u53EA\u9700\u6267\u884C<code>pm2 logs app</code>\u3002\u6216\u8005\u4F7F\u7528 PM2 Plus\uFF0C\u5F53\u5F02\u5E38\u53D1\u751F\u65F6\u83B7\u53D6\u90AE\u4EF6\u901A\u77E5\u548C\u5F02\u5E38\u5206\u6790\u3002</p><h3 id="\u7981\u7528-source-map" tabindex="-1"><a class="header-anchor" href="#\u7981\u7528-source-map" aria-hidden="true">#</a> \u7981\u7528 Source Map</h3><p>\u82E5\u662F\u4F60\u4E0D\u60F3\u8981 PM2 \u53BB\u81EA\u52A8\u652F\u6301 JS Source Map\uFF0C\u4F60\u53EF\u4EE5\u4F7F\u7528<code>--disable-source-map</code>\u9009\u9879\u3002\uFF08\u901A\u8FC7\u547D\u4EE4\u884C\u6216\u751F\u6001\u7CFB\u7EDF\u6587\u4EF6\u90FD\u53EF\u4EE5\uFF09</p><h2 id="transpilers-\u8F6C\u8BD1\u5668" tabindex="-1"><a class="header-anchor" href="#transpilers-\u8F6C\u8BD1\u5668" aria-hidden="true">#</a> transpilers \u8F6C\u8BD1\u5668</h2><h2 id="\u4EE5\u7F16\u7A0B\u65B9\u5F0F\u4F7F\u7528-pm2" tabindex="-1"><a class="header-anchor" href="#\u4EE5\u7F16\u7A0B\u65B9\u5F0F\u4F7F\u7528-pm2" aria-hidden="true">#</a> \u4EE5\u7F16\u7A0B\u65B9\u5F0F\u4F7F\u7528 PM2</h2><p>PM2 \u53EF\u4EE5\u4EE5\u7F16\u7A0B\u65B9\u5F0F\u4F7F\u7528\uFF0C\u8FD9\u610F\u5473\u7740\u4F60\u53EF\u4EE5\u5C06\u8FDB\u7A0B\u7BA1\u7406\u76F4\u63A5\u5185\u5D4C\u5728\u4F60\u7684\u4EE3\u7801\u91CC\uFF0C\u521B\u5EFA\u8FDB\u7A0B\uFF0C\u5373\u4F7F\u4E3B\u811A\u672C\u9000\u51FA\u4E86\uFF0C\u8FD9\u4E9B\u8FDB\u7A0B\u4ECD\u7136\u5B58\u6D3B\u3002</p><h3 id="\u7B80\u5355\u793A\u4F8B" tabindex="-1"><a class="header-anchor" href="#\u7B80\u5355\u793A\u4F8B" aria-hidden="true">#</a> \u7B80\u5355\u793A\u4F8B</h3><p>\u5982\u4E0B\u793A\u4F8B\u5C06\u5C55\u793A\uFF0C\u5982\u4F55\u542F\u52A8<code>app.js</code>\uFF0C\u5E76\u4F20\u5165\u4E00\u4E9B\u914D\u7F6E\u5C5E\u6027\u3002\u4F20\u5165<code>pm2.start</code>\u65B9\u6CD5\u7684\u53C2\u6570\u4E0E\u5728\u751F\u6001\u7CFB\u7EDF\u6587\u4EF6\u91CC\u58F0\u660E\u7684\u5B8C\u5168\u4E00\u6837\u3002</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> pm2 --save\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> pm2 <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;pm2&#39;</span><span class="token punctuation">)</span>\n\npm2<span class="token punctuation">.</span><span class="token function">connect</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">err</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span>err<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">error</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n    process<span class="token punctuation">.</span><span class="token function">exit</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  pm2<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n    script<span class="token operator">:</span> <span class="token string">&#39;app.js&#39;</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">err<span class="token punctuation">,</span> apps</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    pm2<span class="token punctuation">.</span><span class="token function">disconnect</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>err<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token keyword">throw</span> err <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><div class="custom-container warning"><p class="custom-container-title">\u8B66\u544A</p><p>\u82E5\u662F\u4F60\u7684\u811A\u672C\u4E0D\u81EA\u884C\u9000\u51FA\uFF0C\u786E\u4FDD\u4F60\u5728\u4EE3\u7801\u91CC\u624B\u52A8\u8C03\u7528\u4E86<code>pm2.disconnect()</code>\u3002</p></div><h3 id="\u7F16\u7A0B-api" tabindex="-1"><a class="header-anchor" href="#\u7F16\u7A0B-api" aria-hidden="true">#</a> \u7F16\u7A0B API</h3><h4 id="pm2-connect" tabindex="-1"><a class="header-anchor" href="#pm2-connect" aria-hidden="true">#</a> pm2.connect</h4><p>-<code>pm2.connect(errback)</code>\u6216<code>pm2.connect(noDaemonMode, errback)</code> - <code>noDaemonMode</code>: \u9ED8\u8BA4\u4E3A<code>true</code>\u3002\u82E5\u662F\u7B2C\u4E00\u4E2A\u53C2\u6570\u4F20<code>true</code>\uFF0CPM2 \u5C06\u4E0D\u4EE5\u5B88\u62A4\u8FDB\u7A0B\u7684\u65B9\u5F0F\u8FD0\u884C\uFF0C\u5728\u76F8\u5173\u8054\u7684\u811A\u672C\u9000\u51FA\u540E\uFF0CPM2 \u4E5F\u4F1A\u7ED3\u675F\u3002\u82E5\u662F PM2 \u5DF2\u7ECF\u5728\u8FD0\u884C\uFF0C\u4F60\u7684\u811A\u672C\u5C06\u94FE\u63A5\u5230\u5DF2\u5B58\u5728\u7684\u5B88\u62A4\u8FDB\u7A0B\uFF0C\u4F46\u662F\u4E00\u65E6\u4F60\u7684\u811A\u672C\u8FDB\u7A0B\u9000\u51FA\uFF0CPM2 \u4E5F\u4F1A\u7ED3\u675F\u3002 - <code>errback(error)</code>: \u56DE\u8C03\u51FD\u6570\uFF0C\u5B8C\u6210\u521B\u5EFA PM2 \u5B88\u62A4\u8FDB\u7A0B/\u8FDE\u63A5\u5230\u5DF2\u6709\u7684 PM2 \u5B88\u62A4\u8FDB\u7A0B\u540E\u6267\u884C</p><p>\u8BE5\u547D\u4EE4\u8981\u4E0D\u8FDE\u63A5\u5230\u4E00\u4E2A\u6B63\u5728\u8FD0\u884C\u7684 PM2 \u5B88\u62A4\u8FDB\u7A0B\uFF0C\u8981\u4E0D\u521B\u5EFA\u4E00\u4E2A\u65B0\u7684 PM2 \u5B88\u62A4\u8FDB\u7A0B\u3002\u4E00\u65E6\u521B\u5EFA\u4E86\uFF0CPM2 \u8FDB\u7A0B\u5C06\u6301\u7EED\u8FD0\u884C\uFF0C\u5373\u4F7F\u4E3B\u811A\u672C\u9000\u51FA\u4E86\u3002</p><h4 id="pm2-disconnect" tabindex="-1"><a class="header-anchor" href="#pm2-disconnect" aria-hidden="true">#</a> pm2.disconnect()</h4><p>\u65AD\u5F00\u4E0E PM2 \u5B88\u62A4\u8FDB\u7A0B\u7684\u8FDE\u63A5\u3002</p><h4 id="pm2-killdaemon-errback" tabindex="-1"><a class="header-anchor" href="#pm2-killdaemon-errback" aria-hidden="true">#</a> pm2.killDaemon(errback)</h4><p>\u6740\u6389 PM2 \u5B88\u62A4\u8FDB\u7A0B\uFF08\u4E0E<code>pm2 kill</code>\u76F8\u540C\uFF09\u3002\u9700\u8981\u6CE8\u610F\uFF1A</p><ul><li>\u5F53 PM2 \u5B88\u62A4\u8FDB\u7A0B\u88AB\u6740\u6389\u65F6\uFF0C\u5B83\u6240\u6709\u7684\u8FDB\u7A0B\u90FD\u5C06\u88AB\u6740\u6389</li><li>\u5373\u4F7F\u5728\u4F60\u6740\u6389\u5B88\u62A4\u8FDB\u7A0B\u4E4B\u540E\uFF0C\u4F60\u4ECD\u7136\u5FC5\u987B\u660E\u786E\u5730\u4E0E\u5B88\u62A4\u8FDB\u7A0B\u65AD\u5F00\u8FDE\u63A5</li></ul><h4 id="pm2-start" tabindex="-1"><a class="header-anchor" href="#pm2-start" aria-hidden="true">#</a> pm2.start</h4><p><code>pm2.start</code>\u7684\u8C03\u7528\u65B9\u5F0F\u6709\uFF1A</p><ul><li><code>pm2.start(options, errback)</code></li><li><code>pm2.start(jsonConfigFile, errback)</code></li><li><code>pm2.start(script, errback)</code></li><li><code>pm2.start(script, options, errback)</code></li><li><code>pm2.start(script, jsonConfigFile, errback)</code></li></ul><p>\u51FD\u6570\u7684\u53C2\u6570\u8BF4\u660E\u5982\u4E0B\uFF1A</p>', 61);
