const _hoisted_453 = /* @__PURE__ */ createStaticVNode('<h4 id="deploy" tabindex="-1"><a class="header-anchor" href="#deploy" aria-hidden="true">#</a> Deploy</h4><p>\u8FD9\u91CC\u662F\u4E00\u4E9B\u5B9E\u7528\u7684\u547D\u4EE4\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 1. Setup deployment at remote location</span>\npm2 deploy production setup\n\n<span class="token comment"># 2. \u90E8\u7F72</span>\npm2 deploy production\n\n<span class="token comment"># Update remote version</span>\npm2 deploy production update\n\n<span class="token comment"># Revert to -1 deployment</span>\npm2 deploy production revert <span class="token number">1</span>\n\n<span class="token comment"># execute a command on remote servers</span>\npm2 deploy production <span class="token builtin class-name">exec</span> <span class="token string">&quot;pm2 reload all&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h3 id="\u90E8\u7F72\u9009\u9879" tabindex="-1"><a class="header-anchor" href="#\u90E8\u7F72\u9009\u9879" aria-hidden="true">#</a> \u90E8\u7F72\u9009\u9879</h3><p>\u6267\u884C<code>pm2 deploy help</code>\u663E\u793A\u90E8\u7F72\u5E2E\u52A9\u3002</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 deploy <span class="token operator">&lt;</span>configuration_file<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>environment<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>command<span class="token operator">&gt;</span>\n\n  Commands:\n    setup                run remote setup commands\n    update               update deploy to the latest release\n    revert <span class="token punctuation">[</span>n<span class="token punctuation">]</span>           revert to <span class="token punctuation">[</span>n<span class="token punctuation">]</span>th last deployment or <span class="token number">1</span>\n    curr<span class="token punctuation">[</span>ent<span class="token punctuation">]</span>            output current release commit\n    prev<span class="token punctuation">[</span>ious<span class="token punctuation">]</span>           output previous release commit\n    <span class="token builtin class-name">exec</span><span class="token operator">|</span>run <span class="token operator">&lt;</span>cmd<span class="token operator">&gt;</span>       execute the given <span class="token operator">&lt;</span>cmd<span class="token operator">&gt;</span>\n    list                 list previous deploy commits\n    <span class="token punctuation">[</span>ref<span class="token punctuation">]</span>                deploy to <span class="token punctuation">[</span>ref<span class="token punctuation">]</span>, the <span class="token string">&quot;ref&quot;</span> setting, or latest tag\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="\u5F3A\u5236\u90E8\u7F72" tabindex="-1"><a class="header-anchor" href="#\u5F3A\u5236\u90E8\u7F72" aria-hidden="true">#</a> \u5F3A\u5236\u90E8\u7F72</h3><p>\u4F60\u53EF\u80FD\u4F1A\u9047\u5230\u4EE5\u4E0B\u4FE1\u606F\uFF1A</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token operator">--</span><span class="token operator">&gt;</span> Deploying to dev environment\n<span class="token operator">--</span><span class="token operator">&gt;</span> on host <span class="token number">192.168</span><span class="token number">.1</span><span class="token punctuation">.</span><span class="token constant">XX</span>\n\n  push your changes before deploying\n\nDeploy failed\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>\u8FD9\u610F\u5473\u7740\u4F60\u672C\u5730\u6709\u4E00\u4E9B\u4FEE\u6539\u6CA1\u6709\u63A8\u9001\u5230\u4ED3\u5E93\u91CC\uFF0C\u5E76\u4E14\u7531\u4E8E\u90E8\u7F72\u811A\u6B65\u4F1A\u901A\u8FC7<code>git pull</code>\u6765\u83B7\u53D6\u4E0D\u5728\u4F60\u670D\u52A1\u5668\u4E0A\u7684\u4FEE\u6539\u5185\u5BB9\u3002</p><p>\u82E5\u662F\u4F60\u60F3\u8981\u90E8\u7F72\u4F46\u4E0D\u9700\u8981\u63A8\u9001\u4EFB\u4F55\u6570\u636E\uFF0C\u4F60\u53EF\u4EE5\u6DFB\u52A0<code>--force</code>\u9009\u9879\uFF1A</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pm2 deploy ecosystem.json production --force\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="\u8003\u8651\u4E8B\u9879" tabindex="-1"><a class="header-anchor" href="#\u8003\u8651\u4E8B\u9879" aria-hidden="true">#</a> \u8003\u8651\u4E8B\u9879</h3><ul><li>\u4F60\u53EF\u4EE5\u901A\u8FC7\u4F7F\u7528<code>--force</code>\u9009\u9879\u6765\u8DF3\u8FC7\u672C\u5730\u4FEE\u6539\u7684\u68C0\u6D4B</li><li>\u786E\u4FDD\u4F60\u7684\u8FDC\u7A0B\u670D\u52A1\u5668\u6709\u6743\u9650\u514B\u9686\u8FDC\u7A0B\u4ED3\u5E93</li><li>\u4F60\u53EF\u4EE5\u57FA\u4E8E\u4F60\u60F3\u8981\u90E8\u7F72\u7684\u73AF\u5883\uFF0C\u58F0\u660E\u7279\u5B9A\u7684\u73AF\u5883\u53D8\u91CF\u3002\u6BD4\u5982\u82E5\u662F\u4E3A<code>production</code>\u73AF\u5883\u58F0\u660E\u73AF\u5883\u53D8\u91CF\uFF0C\u6DFB\u52A0<code>env_production: { hello: &#39;world&#39; }</code>\u6765\u58F0\u660E\u53D8\u91CF</li><li>\u4F60\u53EF\u4EE5\u5C06<code>apps</code>\u548C<code>deploy</code>\u5185\u5D4C\u5728<code>package.json</code>\u6587\u4EF6\u91CC\uFF08\u800C\u4E0D\u4E00\u5B9A\u8981\u4F7F\u7528\u751F\u6001\u7CFB\u7EDF\u6587\u4EF6\uFF09</li></ul><h3 id="ssh-\u514B\u9686\u9519\u8BEF" tabindex="-1"><a class="header-anchor" href="#ssh-\u514B\u9686\u9519\u8BEF" aria-hidden="true">#</a> SSH \u514B\u9686\u9519\u8BEF</h3><p>\u7EDD\u5927\u591A\u6570\u60C5\u51B5\u4E0B\uFF0C\u8FD9\u4E9B\u9519\u8BEF\u662F\u7531 PM2 \u6CA1\u6709\u6B63\u786E\u7684<code>key</code>\uFF08\u516C\u94A5\uFF09\u53BB\u514B\u9686\u8FDC\u7A0B\u4ED3\u5E93\u5BFC\u81F4\u7684\u3002\u4F60\u9700\u8981\u786E\u4FDD\u5728\u4EE5\u4E0B\u7684\u6BCF\u4E00\u6B65\u91CC\uFF0C<code>key</code>\u90FD\u662F\u53EF\u7528\u7684\u3002</p><ol><li>\u82E5\u4F60\u786E\u5B9A\u4F60\u7684<code>key</code>\u662F\u6B63\u786E\u7684\uFF0C\u5C1D\u8BD5\u5728\u76EE\u6807\u670D\u52A1\u5668\u4E0A\u6267\u884C<code>git clone your_repo.git</code>\u3002\u82E5\u662F\u6210\u529F\uFF0C\u7EE7\u7EED\u4E0B\u4E00\u6B65\uFF1B\u5426\u5219\uFF0C\u8BF7\u786E\u4FDD\u4F60\u7684<code>key</code>\u5B58\u50A8\u5728\u670D\u52A1\u5668\u4E0A\u4EE5\u53CA\u4F60\u7684<code>git account</code>\u4E0A\uFF08\u5C31\u662F github/gitlab \u91CC\u7684\u5427\uFF1F\uFF09</li><li><code>ssh-copy-id</code>\u9ED8\u8BA4\u4F1A\u590D\u5236\u540D\u4E3A<code>id_rsa</code>\u7684\u516C\u94A5\u6587\u4EF6\u3002\u5982\u679C\u8FD9\u4E0D\u662F\u6B63\u786E\u7684\u516C\u94A5\u6587\u4EF6\uFF0C\u6267\u884C<code>ssh-copy-id -i path/to/my/key your_username@server.com</code>\u5C06\u4F60\u7684\u516C\u94A5\u6DFB\u52A0\u5230\uFF08\u670D\u52A1\u5668\u4E0A\u7684\uFF09<code>~/.ssh/authorized_keys</code>\u6587\u4EF6\u91CC</li><li>\u82E5\u662F\u4F60\u83B7\u5F97\u4E86\u5982\u4E0B\u7684\u9519\u8BEF\uFF1A</li></ol><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>--<span class="token operator">&gt;</span> Deploying to production environment\n--<span class="token operator">&gt;</span> on <span class="token function">host</span> mysite.com\n  \u25CB hook pre-setup\n  \u25CB running setup\n  \u25CB cloning git@github.com:user/repo.git\nCloning into <span class="token string">&#39;/var/www/app/source&#39;</span><span class="token punctuation">..</span>.\nPermission denied <span class="token punctuation">(</span>publickey<span class="token punctuation">)</span>.\nfatal: Could not <span class="token builtin class-name">read</span> from remote repository.\n\nPlease <span class="token function">make</span> sure you have the correct access rights and that the repository exists.\n\n**Failed to clone**\n\nDeploy failed\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div>', 18);
